                "initialize(address,address)",
                address(this),
                address(vestingManager)
            )
        );

        vestingDeployer = SecondSwap_VestingDeployer(
            address(vestingDeployerProxy)
        );

        marketplaceSetting = new SecondSwap_MarketplaceSetting({
