            _listingId: 1,
            _amount: amount,
            _referral: address(0)
        });
        vm.stopPrank();

        (uint256 vestingBuyerClaimableAmount, ) = vesting.claimable(vestingBuyer);

        console.log("Buyer claimable amount: ", vestingBuyerClaimableAmount);
    }

