        vesting.createVesting({
            _beneficiary: vestingSeller1,
            _totalAmount: 10e18
        });

        vesting.createVesting({
            _beneficiary: vestingSeller2,
            _totalAmount: 10e18
        });

        // After 10 days, vestingSeller1 claims and then lists 10% of the total amount
        vm.warp(block.timestamp + 10 days);
